    hexi::buffer_adaptor<const std::vector<uint8_t>> adaptor(source_buffer);

    // Check if the requested bytes_to_read is within the available data
    if (bytes_to_read > adaptor.write_ - adaptor.read_) {
        throw std::out_of_range("Requested bytes exceed available data");
    }

    // Use the read function to copy data to a new vector
    std::vector<uint8_t> result(bytes_to_read);
    adaptor.read(result.data(), bytes_to_read);

