struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    std::span<uint8_t> non_const_buffer(buffer.data(), buffer.size());
    hexi::buffer_adaptor adaptor(non_const_buffer);

    DataResult result;

    // Use buffer_adaptor's copy function to preview the first byte (data_type)
    adaptor.copy(&result.data_type, sizeof(uint8_t));

    // Check if buffer has enough data for the header (5 bytes: 1 for data_type + 4 for item_count)
    if (adaptor.size() < 5) {
        return result; // Return empty result if insufficient data
    }

    // Create binary_stream from the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Read item_count (uint32_t)
    uint32_t item_count;
    stream >> item_count;

    // Check if buffer has enough data for all items
    size_t items_size = 0;
    if (result.data_type == 0) {
        items_size = item_count * sizeof(uint32_t);
    } else if (result.data_type == 1) {
        items_size = item_count * sizeof(float);
