    int* ptr1 = allocator.allocate(42);
    std::cout << "1. Allocated first block (value: 42)" << std::endl;
    std::cout << "   - Internally called pop() to remove head from free list" << std::endl;

    // Second allocation - this will use pop() again
    int* ptr2 = allocator.allocate(100);
    std::cout << "2. Allocated second block (value: 100)" << std::endl;
    std::cout << "   - Internally called pop() to remove next head from free list" << std::endl;

    // Third allocation - this will either use remaining free list or fall back to new
    int* ptr3 = allocator.allocate(200);
    std::cout << "3. Allocated third block (value: 200)" << std::endl;
    std::cout << "   - If element_count >= 3, this uses remaining free list" << std::endl;
    std::cout << "   - If element_count < 3, this falls back to system allocator" << std::endl;

    // Deallocate first block - this will use push() to add to head of free list
    allocator.deallocate(ptr1);
    std::cout << "4. Deallocated first block" << std::endl;
    std::cout << "   - Internally called push() to add to head of free list" << std::endl;

    // Deallocate second block - this will use push() again
    allocator.deallocate(ptr2);
    std::cout << "5. Deallocated second block" << std::endl;
    std::cout << "   - Internally called push() to add to head of free list" << std::endl;

    // Fourth allocation - this will reuse the deallocated blocks due to push()
    int* ptr4 = allocator.allocate(300);
    std::cout << "6. Allocated fourth block (value: 300)" << std::endl;
    std::cout << "   - Reuses previously deallocated block (push() made it available)" << std::endl;

    // Demonstrate fallback to system allocator when preallocated blocks are exhausted
    int* ptr5 = nullptr;
    for (size_t i = 0; i < element_count + 5; ++i) {
        ptr5 = allocator.allocate(static_cast<int>(i * 10));
    }
    std::cout << "7. Allocated beyond preallocated capacity" << std::endl;
    std::cout << "   - Falls back to system allocator (new) when free list is empty" << std::endl;

    // Clean up remaining allocations
    allocator.deallocate(ptr3);
    allocator.deallocate(ptr4);
    allocator.deallocate(ptr5);

    std::cout << "-----------------------------------------------" << std::endl;
    std::cout << "Free list management demonstrated successfully!" << std::endl;
}
```

This implementation demonstrates the internal free list management by:

1. Creating a `block_allocator` instance
2. Performing multiple allocations to show how `pop()` retrieves blocks from the free list
3. Performing deallocations to show how `push()` returns blocks to the free list
4. Demonstrating the fallback behavior when the preallocated slab is exhausted
5. Showing the LIFO (Last-In-First-Out) nature of the free list management

The comments explain the internal behavior of `push()` and `pop()` methods as they relate to the free list management, fulfilling the exam requirements.

