#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold all chunks
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    std::size_t total_written = 0;

    // Iterate through each chunk
    for (const auto& chunk : chunks) {
        // Check available space before writing
        if (adaptor.free() < chunk.size()) {
            // Handle insufficient space (in real scenario, you might throw an exception or resize)
            continue; // Skip this chunk if no space
        }

        // Write the chunk data
        adaptor.write(chunk.data(), chunk.size());

        // Update total written count
        total_written += chunk.size();
    }

    // Return the total size written
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> result;

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read in this iteration
        std::size_t bytes_to_read = std::min(adaptor.size(), chunk_size);

        // Create temporary buffer for reading
        std::vector<uint8_t> temp_chunk(bytes_to_read);

        // Read the data
        adaptor.read(temp_chunk.data(), bytes_to_read);

        // Append to result
        result.insert(result.end(), temp_chunk.begin(), temp_chunk.end());

        // Optional: Add a small delay or yield to prevent tight loops
        // std::this_thread::sleep_for(std::chrono::microseconds(1));
    }

    return result;
}
