        // Serialization: convert from native to little-endian
        adaptor.serialise(sensor_id);

        for (auto& temp : temperatures) {
            float converted = hexi::endian::conditional_reverse(
                static_cast<float>(temp), 
                std::endian::native, 
                std::endian::little
            );
            adaptor.write(converted);
        }

        double converted_pressure = hexi::endian::conditional_reverse(
            pressure, 
            std::endian::native, 
            std::endian::little
        );
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        adaptor.deserialise(sensor_id);

        temperatures.clear();
        for (size_t i = 0; i < temperatures.size(); ++i) {
            float temp_value;
            adaptor.read(temp_value);
            hexi::endian::little_to_native_inplace(temp_value);
            temperatures.push_back(temp_value);
        }

        double pressure_value;
        adaptor.read(pressure_value);
        hexi::endian::little_to_native_inplace(pressure_value);
        pressure = pressure_value;
    }
};

