    // Create adaptor and enforce bounds for sensor_id
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));
    adaptor.enforce_read_bounds(sizeof(uint32_t));

    // Extract sensor name using view (null-terminated)
    info.sensor_name = adaptor.view();

    // Read sensor_id
    adaptor.read(&info.sensor_id);

    // Skip remaining data
    size_t remaining = buffer.size() - sizeof(uint32_t) - info.sensor_name.size();
    if (remaining > 0) {
        adaptor.skip(remaining);
    }

    return info;
}
